class SecureOAuthAuthorizationServer:
    """
    OAuth 2.0 Authorization Server with EXACT redirect URI matching.

    Why exact matching?
    - Prefix matching allows open redirects (e.g., registered: https://app.com,
      attacker uses: https://app.com.evil.com)
    - Substring matching is even worse
    - RFC 6749 Section 3.1.2.3 requires exact string matching
    - OAuth 2.0 Security BCP (RFC 9700) mandates exact matching

    To support multiple environments, register each redirect URI explicitly.
    """

    def __init__(self):
        self._clients: dict[str, OAuthClient] = {}
        self._authorization_codes: dict[str, AuthorizationCode] = {}
        self._access_tokens: dict[str, AccessToken] = {}
        self._code_lifetime = 600  # 10 minutes
        self._token_lifetime = 3600  # 1 hour

    def register_client(
        self,
        client_name: str,
        redirect_uris: list[str],
        allowed_scopes: Optional[set[str]] = None,
    ) -> tuple[str, str]:
        """
        Register an OAuth client with EXACT redirect URIs.

        For multiple environments, register each one:
            redirect_uris=[
                "https://localhost:3000/callback",        # local dev
                "https://dev.myapp.com/callback",         # dev
                "https://staging.myapp.com/callback",     # staging
                "https://myapp.com/callback",             # production
            ]
        """
